/**
 * Build an n8n-API-safe workflow payload
 * using a strict allowlist (NOT a denylist).
 */

// --------------------
// Helpers
// --------------------

function pick(obj, allowedKeys) {
  if (!obj || typeof obj !== 'object') return {};
  return Object.fromEntries(
    Object.entries(obj).filter(([key]) => allowedKeys.includes(key))
  );
}

function cleanNode(node) {
  return {
    id: node.id,
    name: node.name,
    type: node.type,
    typeVersion: node.typeVersion,
    position: node.position,
    parameters: node.parameters ?? {},
    credentials: node.credentials ?? {},
    disabled: node.disabled ?? false,
    notes: node.notes,
    notesInFlow: node.notesInFlow,
  };
}

// --------------------
// ENTRY POINT
// --------------------

const source = $json.data;

// ---- Top-level allowlist ----
const workflow = {
  name: source.name,
  nodes: source.nodes.map(cleanNode),
  connections: source.connections,
};

// ---- Settings allowlist ----
const ALLOWED_SETTINGS = [
  'timezone',
  'executionTimeout',
  'saveExecutionProgress',
  'saveManualExecutions',
  'errorWorkflowId',
];

if (source.settings) {
  const cleanedSettings = pick(source.settings, ALLOWED_SETTINGS);
  if (Object.keys(cleanedSettings).length > 0) {
    workflow.settings = cleanedSettings;
  }
}

// ---- Optional staticData ----
if (source.staticData) {
  workflow.staticData = source.staticData;
}

return workflow;

const data = $input.first().json.data;

const options = data
  .map(item => `{
  "option": "${item.repo_name}"}`)
  .join(",");

return {
  json: {
    options,
  },
};

const data = $input.first().json.allFiles;

const options = data
  .map(item => `{
  "option": "${item.name}"}`)
  .join(",");

return {
  json: {
    options,
  },
};

parameters.content:
## How it works 🧠 (Cue Logic Explanation)
This section traverses a GitHub repository using a queue-based state object inside a single workflow execution.

It:
	•	Starts at the repository root
	•	Fetches folder contents
	•	Adds subfolders to a queue
	•	Collects discovered files
	•	Repeats until no folders remain

Traversal is controlled entirely through a single state object.

## Setup steps ⚙️
1. Add your GitHub credentials (Personal Access Token with repo access).
2. Add your n8n API key (Settings → API Keys).
3. Configure the Repo Owner form field:
   • Keep Field Name: `Repo Owner`
   • Keep Label: `Repo Owner`
   • Keep Type: `Dropdown`
   • Only update the default value and dropdown options to match your GitHub account or organisation.

That’s it. The workflow handles everything else automatically.

## Technical breakdown 🤓
### State structure
```
return [{
  json: {
    pendingPaths: [""],   // root folder
    currentPath: "",
    allFiles: []
  }
}];
```
	•	pendingPaths → Queue of folders left to process
	•	currentPath → Folder currently being fetched
	•	allFiles → Accumulated files discovered so far

The loop continues while:

pendingPaths.length > 0

### Step 1: Select next folder
const state = $json;
state.currentPath = state.pendingPaths.shift();
return [{ json: state }];

	•	Removes the next folder from the queue
	•	Assigns it to currentPath
	•	Ensures one-at-a-time processing

### Step 2 — Fetch folder contents (GitHub node)

GitHub returns objects like:
```
{
  "type": "file" | "dir",
  "path": "..."
}
```
Each item is merged back into state.

### Step 3 — Update state
```
const state = $('Set Current Path').all()[0].json;

state.pendingPaths ??= [];
state.allFiles ??= [];

const entries = $input.all().map(i => i.json);

for (const entry of entries) {
  if (entry.type === "dir") {
    state.pendingPaths.push(entry.path);
  } else if (entry.type === "file") {
    state.allFiles.push(entry);
  }
}

return [{ json: state }];
```
	•	Directories → appended to pendingPaths
	•	Files → appended to allFiles
	•	State is returned as a single item

The loop repeats until no folders remain.

### Termination condition
When:

`pendingPaths.length === 0`

Traversal is complete.

At this point:

allFiles contains every file in the repository.

Only then does the workflow fan out downstream.
